import { useState } from "react";
import { motion } from "framer-motion";
import { Youtube, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import YouTubeExpandedContent, { YOUTUBE_EXPANDED_FAQS } from "@/components/YouTubeExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}
function fmtViews(n: number) {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M views`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(0)}K views`;
  return `${n} views`;
}


const FAQS = [
  { q: "What is CPM on YouTube?", a: "CPM (Cost Per Mille) is the amount advertisers pay per 1,000 ad impressions on your videos. It's set by advertisers bidding in Google's ad auction - you don't control CPM directly, but your niche, audience location, and content type influence it." },
  { q: "What's the difference between CPM and RPM?", a: "CPM is what advertisers pay per 1,000 impressions. RPM (Revenue Per Mille) is your actual earnings per 1,000 views after YouTube's 45% cut. RPM - CPM  x  0.55. This calculator shows both." },
  { q: "How can I increase my YouTube CPM?", a: "Target high-CPM niches (finance, tech, business, real estate). Create content that attracts US/UK/AU audiences. Longer videos with mid-roll ads boost CPM. Q4 (Oct-Dec) consistently yields the highest CPM due to advertiser spend spikes." },
  { q: "Why does my CPM fluctuate month to month?", a: "CPM is driven by advertiser demand, which varies seasonally. Q1 sees steep drops after Q4's highs. Advertiser competition in your niche also affects CPM. Over a full year, average CPM gives a better picture than any single month." },
  { q: "What is a good RPM for YouTube?", a: "An RPM of $1-$3 is common for general content. $3-$6 is good. $6-$15+ is excellent and typically indicates a high-CPM niche (finance, software, business). Your RPM in YouTube Analytics is the most reliable performance indicator." },
  { q: "Why is my CPM high but my earnings are low?", a: "High CPM with low earnings usually means your monetized playback rate (what % of views show ads) is low. This happens with short videos, un-monetized audiences, or viewers who skip ads very quickly. Longer videos with mid-rolls improve total ad revenue." },
  { q: "Does ad type affect CPM?", a: "Yes. Skippable ads (TrueView) have lower CPMs because advertisers only pay when viewers watch 30+ seconds. Non-skippable ads have higher CPMs. Display ads have the lowest CPMs. YouTube's algorithm optimizes ad type per viewer." },
  { q: "How do I find my actual CPM in YouTube Studio?", a: "Go to YouTube Studio - Analytics - Revenue tab. You'll see your CPM (what advertisers paid) and RPM (what you earned) per 1,000 views. These metrics are also available broken down by video, traffic source, and geography." },
];

const EXPANDED_FAQS = YOUTUBE_EXPANDED_FAQS.cpm;

export default function YouTubeCPMCalculator() {
  useCurrencyVersion();
  const [revenue, setRevenue] = useState(500);
  const [views, setViews] = useState(200000);

  const rpm = views > 0 ? (revenue / views) * 1000 : 0;
  const grossCPM = rpm / 0.55;
  const ytShare = revenue / 0.55 * 0.45;

  const viewScenarios = [50000, 100000, 250000, 500000, 1000000].map(v => ({
    v,
    yourRevenue: (v / 1000) * rpm,
    gross: (v / 1000) * grossCPM,
  }));

  return (
    <>
      <SEOHead
        title="Free YouTube CPM Calculator Online 2025 - Calculate CPM and RPM Instantly | CalcHive"
        description="Free YouTube CPM and RPM calculator online. Enter your revenue and views to instantly calculate your exact CPM and RPM. 100% free for all YouTubers, no account needed, works on all devices."
        canonical="/youtube-cpm-calculator"
        keywords="free youtube CPM calculator, youtube RPM calculator free, calculate youtube CPM online free, what is youtube CPM, youtube CPM RPM calculator free online, youtube revenue per thousand views free calculator"
        category="YouTube"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-950/50 px-3 py-1 rounded-full mb-4">
            <Youtube className="w-3.5 h-3.5" /> YouTube
          </span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free YouTube CPM Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free youtube CPM calculator to enter your revenue and views, then calculate youtube CPM online free along with RPM. This youtube RPM calculator free tool answers what is youtube CPM, works as a youtube CPM RPM calculator free online, and gives a youtube revenue per thousand views free calculator for creators on any device.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="yt-revenue" label="YouTube Revenue (your 55% earnings)" value={revenue} min={1} max={50000} step={10} onChange={setRevenue} format={v => fmt(v)} testId="input-revenue" />
            <SliderInput id="yt-views" label="Monthly Views" value={views} min={1000} max={10000000} step={1000} onChange={setViews} format={fmtViews} testId="input-views" />
          </div>
          <motion.div key={`${revenue}-${views}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-red-500 to-red-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Your RPM (per 1,000 views)</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-rpm">{fmt(rpm)}</p>
              <p className="text-white/70 text-sm mt-1">what you earn per 1,000 views</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Advertiser CPM", value: fmt(grossCPM), testId: "result-cpm" },
                { label: "Your 55% Cut", value: fmt(revenue) },
                { label: "YouTube's 45%", value: fmt(ytShare), red: true },
              ].map(({ label, value, red, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-lg font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`} data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">What is YouTube CPM and RPM and What is the Difference</h2>
          <p className="text-muted-foreground leading-relaxed">RPM is derived from your actual earnings and views. CPM is derived from RPM by dividing by the 55% creator share. Both metrics help you understand your channel's advertising value and project future income at different view levels.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>RPM = (Your Earnings  x  Views)  x  1,000</p>
            <p>Advertiser CPM = RPM  x  0.55</p>
            <p>YouTube's share = Gross Revenue  x  0.45</p>
            <p className="text-xs text-muted-foreground mt-2">Gross Revenue = Advertiser CPM  x  (Views  x  1,000)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your YouTube CPM for Free</h2>
          <p className="text-muted-foreground leading-relaxed">CPM is calculated from advertiser spend per 1,000 ad impressions, while RPM is your creator revenue per 1,000 views. Enter your real earnings and views above to calculate both instantly.</p>

          <h2 className="text-2xl font-bold text-foreground">What is a Good CPM on YouTube</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Monthly Views", "Your Earnings (55%)", "Gross Ad Spend (100%)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {viewScenarios.map(({ v, yourRevenue, gross }) => (
                  <tr key={v} className={`hover:bg-muted/30 ${v === views ? "bg-red-50 dark:bg-red-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-semibold text-foreground">{fmtViews(v)}</td>
                    <td className="py-2.5 px-4 text-red-600 dark:text-red-400 font-semibold">{fmt(yourRevenue)}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{fmt(gross)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free CPM and RPM Calculator for Every YouTube Creator</h2>
          <p className="text-muted-foreground leading-relaxed">Use the projections to benchmark future income, compare channels, and understand whether your niche is earning a low, average, or premium CPM.</p>
        </section>
        <YouTubeExpandedContent kind="cpm" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/youtube-cpm-calculator" headingLevel="h3" />
      </main>
    </>
  );
}




